class Solution:
    def magicalString(self, n):
        if n <= 0:
            return 0
        if n <= 3:
            return 1
        s = [1, 2, 2]
        symbol = 1
        i = 2
        while len(s) < n:
            count = s[i]
            s.extend([symbol] * count)
            symbol = 3 - symbol
            i += 1
        return sum(1 for x in s[:n] if x == 1)

