class Solution:
    def magicalString(self, n):
        if n == 0:
            return 0
        if n <= 3:
            return 1
        s = [1, 2, 2]
        head = 2
        ones = 1
        nxt = 1
        while len(s) < n:
            for _ in range(s[head]):
                s.append(nxt)
                if nxt == 1 and len(s) <= n:
                    ones += 1
                if len(s) >= n:
                    break
            nxt ^= 3
            head += 1
        return ones

