var magicalString = function(n) {
    if (n === 0) return 0;
    if (n <= 3) return 1;
    const s = [1, 2, 2];
    let head = 2;
    let ones = 1;
    let nxt = 1;
    while (s.length < n) {
        const count = s[head];
        for (let j = 0; j < count; j++) {
            s.push(nxt);
            if (nxt === 1 && s.length <= n) ones++;
            if (s.length >= n) break;
        }
        nxt ^= 3;
        head++;
    }
    return ones;
};
